args.command:
node -e "
const Ajv = require('ajv');
const fs = require('fs');

try {
  const ajv = new Ajv();
  const schema = JSON.parse(fs.readFileSync('schema.json', 'utf-8'));
  const profile = JSON.parse(fs.readFileSync('profile.json', 'utf-8'));

  const validate = ajv.compile(schema);
  const valid = validate(profile);

  if (valid) {
    console.log('✓ VALID: profile.json passes schema.json');
    console.log('Keys at top level:', Object.keys(profile));
    console.log('Keys in owner object:', Object.keys(profile.owner));
  } else {
    console.log('✗ INVALID: ' + JSON.stringify(validate.errors));
  }
} catch(e) {
  console.log('Error: ' + e.message);
}
"
